      "name": "\u0425\u0440\u0430\u043C. \u0422\u0440\u0438 \u041A\u0440\u0435\u0441\u0442\u0430. \u0421\u043E\u0444\u0438\u044F",
      "short": "\u0425\u0440\u0430\u043C",
      "emoji": "\u26EA",
      "summary": "\u0423\u0437\u0435\u043B \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442 \u043C\u0430\u043A\u0441\u0438\u043C\u0430\u043B\u044C\u043D\u044B\u0439 \u043A\u043E\u043D\u0446\u0435\u043F\u0442\u0443\u0430\u043B\u044C\u043D\u044B\u0439 \u0441\u0434\u0432\u0438\u0433 \u043A\u043D\u0438\u0433\u0438: \u043F\u0435\u0440\u0435\u0438\u043C\u0435\u043D\u043E\u0432\u044B\u0432\u0430\u0435\u0442 \u042F\u0441\u043D\u0443 \u0432 \u0425\u0440\u0430\u043C\u043E\u0432\u043E\u0435 \u0423\u0447\u0435\u043D\u0438\u0435 (\u043E\u0434\u043D\u043E \u0438\u0437 12 \u0443\u0447\u0435\u0431\u043D\u0438\u043A\u043E\u0432 \xAB\u041A\u043E\u043B\u043E\u043C\u0435\u043D\u0441\u043A\u043E\u0433\u043E \u041A\u043E\u0441\u0442\u0440\u0430\xBB); \u0432\u0432\u043E\u0434\u0438\u0442 \u0441\u043A\u0432\u043E\u0437\u043D\u0443\u044E \u043D\u0443\u043C\u0435\u0440\u0430\u0446\u0438\u044E 0\u201311; \u0434\u0430\u0451\u0442 \u0433\u043B\u0430\u0432\u043D\u0443\u044E \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u043D\u0443\u044E \u043D\u0430\u0445\u043E\u0434\u043A\u0443 \u2014 \u0422\u0440\u0438 \u041A\u0440\u0435\u0441\u0442\u0430 (\u041E\u043F\u043E\u0440\u043D\u044B\u0439 0-3-6-9, \u0422\u0435\u043F\u043B\u043E\u0432\u043E\u0439 1-4-7-10, \u0412\u0435\u0440\u044B 2-5-8-11), \u0441\u043E\u0435\u0434\u0438\u043D\u0451\u043D\u043D\u044B\u0445 \u0446\u0435\u043D\u0442\u0440\u0430\u043C\u0438 \u0432 12-\u043B\u0443\u0447\u0435\u0432\u0443\u044E \u0417\u0432\u0435\u0437\u0434\u0443; \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u0435\u0442 \u043A\u0430\u0436\u0434\u044B\u0439 \u041A\u0440\u0435\u0441\u0442 \u0447\u0435\u0440\u0435\u0437 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0438\u043C\u0435\u043D\u0430; \u0438\u0434\u0435\u043D\u0442\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442 \u0445\u0440\u0438\u0441\u0442\u0438\u0430\u043D\u0441\u043A\u0443\u044E \u0442\u0440\u0438\u0430\u0434\u0443 \u0412\u0435\u0440\u0430-\u041D\u0430\u0434\u0435\u0436\u0434\u0430-\u041B\u044E\u0431\u043E\u0432\u044C \u043A\u0430\u043A \u0438\u043C\u0435\u043D\u043D\u043E \u044D\u0442\u0438 \u0422\u0440\u0438 \u041A\u0440\u0435\u0441\u0442\u0430, \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0451\u043D\u043D\u044B\u0435 \u0432 \u0421\u043E\u0444\u0438\u044E; \u0432\u0432\u043E\u0434\u0438\u0442 \u043C\u0435\u0442\u0430\u0444\u043E\u0440\u0443 \u041F\u043E\u043B\u043E\u0447\u0435\u043A \u0438 \u042F\u0431\u043B\u043E\u0447\u043A\u0430 \u043D\u0430 \u0411\u043B\u044E\u0434\u0435\u0447\u043A\u0435.",
