      "category": "T4.K3",
      "kind": "list",
      "term": "\u041E\u0434\u043D\u043E\u0441\u043B\u043E\u0432\u043D\u044B\u0435 \u0438\u043C\u0435\u043D\u0430-\xAB\u0441\u0435\u043C\u0435\u0439\u0441\u0442\u0432\u043E \u0410\u043B\u043C\u0430\u0437\u0430\xBB",
      "quote": "\xAB\u0410\u043B\u043C\u0430\u0437\xBB. \u0412\u043E\u0442 \u043E\u0447\u0435\u043D\u044C \u0443\u0434\u043E\u0431\u043D\u043E\u0435 \u043D\u0430\u0437\u0432\u0430\u043D\u0438\u0435 \u044D\u0442\u043E\u0433\u043E \u0447\u0435\u0440\u0442\u0435\u0436\u0430. \u0418\u043B\u0438 \xAB\u0414\u0438\u0430\u043C\u0430\u043D\u0442\xBB\u2026 \u0410 \u0435\u0449\u0451 \xAB\u0411\u0440\u0438\u043B\u043B\u0438\u0430\u043D\u0442\xBB\u2026 \u0435\u0441\u0442\u044C \u0435\u0449\u0451 \u043B\u0430\u0442\u0438\u043D\u0441\u043A\u043E\u0435 \u0441\u043B\u043E\u0432\u043E \xABAdamas\xBB. \u0418\u043B\u0438 \xAB\u0410\u0434\u0430\u043C\u0430\u0441\xBB.",
