      "theme": "osi-kresty",
      "themeFull": "T4",
      "category": "T4.K5",
      "kind": "postulate",
      "term": null,
      "quote": "\u042F\u0441\u043D\u0430 \u0438 \u0435\u0441\u0442\u044C \u0443\u0447\u0435\u043D\u0438\u0435 \u043E \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0438 \u043E \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u043F\u043E\u043B\u043E\u0436\u043D\u043E\u0441\u0442\u0438. \u042F\u0441\u043D\u0430 \u0443\u0447\u0438\u0442 \u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u0432\u0441\u044F\u043A\u0430\u044F \u0432\u0435\u0449\u044C \u0432 \u044D\u0442\u043E\u043C \u043C\u0438\u0440\u0435 \u0435\u0441\u0442\u044C \u0441 \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u043F\u043E\u043B\u043E\u0436\u043D\u043E\u0441\u0442\u044C\u044E. \u0423 \u0432\u0441\u044F\u043A\u043E\u0439 \u0432\u0435\u0449\u0438. \u0423 \u0432\u0441\u0435\u0433\u043E \u0435\u0441\u0442\u044C \u043E\u0442\u0440\u0430\u0436\u0435\u043D\u0438\u0435 \u0432 \u041C\u0438\u0440\u043E\u0432\u043E\u043C \u0417\u0435\u0440\u043A\u0430\u043B\u0435.",
