      "term": "\u0426\u0435\u043F\u043E\u0447\u043A\u0430 \u0440\u043E\u0441\u0442\u0430 \u0441\u0432\u0435\u0442\u0430",
      "quote": "\u0421\u0432\u0435\u0442 \u0440\u0430\u0441\u0442\u0451\u0442 \u0432 \u043F\u044F\u0442\u0438 \u0432\u0440\u0435\u043C\u0435\u043D\u0430\u0445: \u0432\u043D\u0430\u0447\u0430\u043B\u0435 \u0440\u0430\u0441\u0442\u0451\u0442 \u0432 \u0441\u0430\u043C\u043E\u043C \u0441\u0432\u043E\u0451\u043C \u041F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0438. \u0422\u0443\u0442 \u0436\u0435 \u043E\u043D \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442 \u0432 \u0423\u0442\u0440\u0435\u043D\u043D\u0435\u0439 \u0417\u0430\u0440\u0435 \u0432 \u043D\u0435\u044F\u0432\u043D\u043E\u043C \u0432\u0438\u0434\u0435, \u043F\u043E\u0442\u043E\u043C \u2014 \u0441 \u0412\u044B\u0445\u043E\u0434\u043E\u043C \u0421\u043E\u043B\u043D\u0446\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0438 \u0434\u0430\u043B\u044C\u0448\u0435 \u0440\u0430\u0441\u0442\u0451\u0442 \u0432 \u041F\u043E\u0434\u044A\u0451\u043C\u0435 \u0421\u043E\u043B\u043D\u0446\u0430 \u0443\u0436\u0435 \u0432 \u044F\u0432\u043D\u043E\u043C \u0432\u0438\u0434\u0435. \u0418 \u0443\u0436\u0435 \u0434\u043E \u0441\u0432\u043E\u0435\u0433\u043E \u043F\u0440\u0435\u0434\u0435\u043B\u0430 \u0432 \u041F\u0435\u0440\u0435\u043B\u043E\u043C \u043A\u043E \u0414\u043D\u044E.",
