      "theme": "chashi-vesy",
      "themeFull": "T6",
      "category": "T6.K2",
      "kind": "postulate",
      "term": null,
      "quote": "\u0412 \u0443\u0442\u0440\u0435\u043D\u043D\u0435\u043C \u0441\u0440\u0430\u0436\u0435\u043D\u0438\u0438 \u043C\u0435\u0436\u0434\u0443 \u0441\u0432\u0435\u0442\u043E\u043C \u0438 \u0442\u044C\u043C\u043E\u0439, \u0432 \u0441\u0440\u0430\u0436\u0435\u043D\u0438\u0438 \u043D\u0430 \u0432\u043E\u0441\u0442\u043E\u043A\u0435, \u0441\u0432\u0435\u0442 \u043F\u043E\u0431\u0435\u0436\u0434\u0430\u0435\u0442 \u0442\u044C\u043C\u0443. \u0418 \u043F\u043E\u0431\u0435\u0436\u0434\u0430\u0435\u0442 \u0435\u0451 \u0443\u0432\u0435\u0440\u0435\u043D\u043D\u043E, \u0431\u044B\u0441\u0442\u0440\u043E, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0439, \u043A\u043E\u0433\u0434\u0430 \u0442\u043E\u0447\u043D\u043E \u044D\u0442\u043E \u043F\u0440\u043E\u0438\u0437\u043E\u0448\u043B\u043E.",
