      "term": "\u042F\u0441\u043D\u0430 \u0421\u0443\u0442o\u043A \u0441 \u043B\u0438\u0446\u0430\u043C\u0438 \u041F\u0440\u0430\u043D",
      "quote": "\u0422\u0430\u043A\u0430\u044F \u042F\u0441\u043D\u0430 \u0421\u0443\u0442o\u043A \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \xAB\u041F\u043E\u0441\u0442\u0443\u043B\u0430\u0442\xBB \u0438\u043B\u0438 \xAB\u041F\u0443\u0440\u0430\u043D\u0430\xBB. \u041D\u0430 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435 \u0438 \u043D\u0430 \u0432\u0435\u0434\u0438\u0439\u0441\u043A\u043E\u043C \xAB\u041F\u043E\u0441\u0442\u0443\u043B\u0430\u0442\xBB \u043D\u0430\u0437\u044B\u0432\u0430\u044E\u0442 \xAB\u041F\u0443\u0440\u0430\u043D\u0430\xBB. \u0421\u043B\u043E\u0432\u043E \xAB\u041F\u0443\u0440\u0430\u043D\u0430\xBB \u0435\u0441\u0442\u044C \u0441\u0436\u0430\u0442\u0438\u0435 \u043F\u043E \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u044B\u043C \u043F\u0440\u0430\u0432\u0438\u043B\u0430\u043C \u0441\u043B\u043E\u0432\u0430 \xAB\u041F\u043E\u0441\u0442\u0443\u043B\u0430\u0442\xBB. \u0420\u0430\u0437\u0432\u0451\u0440\u043D\u0443\u0442\u043E\u0435 \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u0435 \u0432\u0441\u0435\u0445 \u0432\u0440\u0435\u043C\u0451\u043D \u042F\u0441\u043D\u044B \u0421\u0443\u0442o\u043A \u0435\u0441\u0442\u044C \xAB\u041F\u043E\u0441\u0442\u0443\u043B\u0430\u0442\xBB. \u0418\u043B\u0438 \xAB\u041F\u043E\u043F\u0443\u043B\u044F\u0440\u0438\u043D\xBB. \u041D\u0430 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435 \xAB\u0423\u043F\u0430 \u043F\u0443\u0440\u0430\u043D\u0430\xBB.",
