      "term": "\u0418\u043C\u0435\u043D\u0430 \u043B\u0443\u0447\u0435\u0439 \u041E\u043F\u043E\u0440\u043D\u043E\u0433\u043E \u041A\u0440\u0435\u0441\u0442\u0430 \u042F\u0441\u043D\u044B \u0413\u043E\u0434\u0430",
      "quote": "\u0415\u0433\u043E \u0412\u043E\u0441\u0442\u043E\u0447\u043D\u044B\u0439 3-\u0425\u0410 \u041B\u0443\u0447 \u0432 \u042F\u0441\u043D\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \xAB\u041C\u0430\u0439\u0441\u043A\u0438\u0439 \u0424\u043B\u0430\u0433\xBB. \u041D\u043E \u0440\u0430\u043D\u044C\u0448\u0435 \u043E\u043D \u043D\u0430\u0437\u044B\u0432\u0430\u043B\u0441\u044F \xAB\u0424\u043B\u0430\u0433 \u0412\u0435\u0441\u043D\u044B\xBB. \xAB\u0410\u043F\u0440\u0435\u043B\u044C\u0441\u043A\u0438\u0439 \u0424\u043B\u0430\u0433\xBB. \u0415\u0433\u043E \u0417\u0430\u043F\u0430\u0434\u043D\u044B\u0439 \u041B\u0443\u0447 9-\u0424\u041E \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \xAB\u0424\u043B\u0430\u0436\u043E\u043A\xBB. \u0418\u043B\u0438 \xAB\u0424\u043B\u0430\u0436\u043E\u043A \u041E\u0441\u0435\u043D\u043D\u0438\u0439\xBB. \xAB\u041E\u043A\u0442\u044F\u0431\u0440\u044C\u0441\u043A\u0438\u0439 \u0424\u043B\u0430\u0436\u043E\u043A\xBB.",
